OmniUiCard.stylingConfiguration:
{"styleObjects":{},"customStyles":".block-header-heading{
 width: 100% !important; 
 background-color: #f3f3f3;
 height: 38px; 
}
.slds-form-element__label{
 padding-botton:10px;
 color: #7E8C8D;
 font-size: 13px;
}
.field-value{
 margin-top: 4px;
 display: block;
}
.field-display{
 height: 50px;
 padding-left:10px;
 padding-top:5px;
 margin-bottom: 5px;
}
.water-advisory-banner {
 display: flex;
 align-items: center; /* vertical center */
 background: #fdb913;
 color: #111;
 padding: 12px 24px;
 width: 100%;
 border: none;
 box-shadow: none;
}

/* Row container */
.wateradvisoryrow {
 display: flex !important;
 align-items: center; /* keep this */
}

/* Icon container */
.WaterAdvisoryBannerBlockIconContainer {
 width: 20px !important;
 min-width: 20px !important;
 flex: 0 0 20px !important;

 display: flex;
 align-items: center;
 justify-content: center;

 margin-right: 10px;
 padding: 0 !important;

 align-self: center; /* ✅ THIS is the key */
}

/* Warning icon */
.WaterAdvisoryBannerBlockWarningIcon {
 width: 16px !important;
 height: 16px !important;
 fill: #000 !important;
 display: block;
 margin: auto; /* centers inside container */
}

/* Text container */
.water-advisory-content {
 display: flex;
 flex-direction: column;
 flex: 1;
 padding: 0 !important;
 margin: 0 !important;
}

/* Title */
.water-advisory-title {
 font-weight: 700;
 font-size: 14px;
 line-height: 1.25;
 margin: 0;
 color: #111;
}

/* Reason text */
.water-advisory-reason {
 font-size: 13px;
 line-height: 1.25;
 margin-top: 2px;
 color: #111;
}"}
